#include <vector>
#include <queue>
#include <tuple>
#include <climits>
#include <algorithm>

using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();

    // Directions for normal moves: right and down
    vector<pair<int, int>> dirs = {{0, 1}, {1, 0}};

    // Priority queue: (total_cost, i, j, remaining_k)
    priority_queue<tuple<long long, int, int, int>, 
                   vector<tuple<long long, int, int, int>>, 
                   greater<tuple<long long, int, int, int>>> pq;

    // Distance matrix: dist[i][j][k] = min cost to reach (i,j) with k teleports left
    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(k + 1, LLONG_MAX)));

    // Initialize the starting point
    pq.emplace(0, 0, 0, k);
    dist[0][0][k] = 0;

    while (!pq.empty()) {
        auto [cost, i, j, rem_k] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return cost;
        }

        if (cost > dist[i][j][rem_k]) {
            continue;
        }

        // Normal moves
        for (auto [di, dj] : dirs) {
            int ni = i + di;
            int nj = j + dj;
            if (ni < m && nj < n) {
                long long new_cost = cost + grid[ni][nj];
                if (new_cost < dist[ni][nj][rem_k]) {
                    dist[ni][nj][rem_k] = new_cost;
                    pq.emplace(new_cost, ni, nj, rem_k);
                }
            }
        }

        // Teleport move if remaining teleports > 0
        if (rem_k > 0) {
            for (int ni = 0; ni < m; ++ni) {
                for (int nj = 0; nj < n; ++nj) {
                    if (ni == i && nj == j) continue;
                    if (grid[ni][nj] <= grid[i][j]) {
                        if (cost < dist[ni][nj][rem_k - 1]) {
                            dist[ni][nj][rem_k - 1] = cost;
                            pq.emplace(cost, ni, nj, rem_k - 1);
                        }
                    }
                }
            }
        }
    }

    // Should not reach here if there's a valid path
    return -1;
}

