function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;
    const dirs = [[0, 1], [1, 0]]; // right and down

    // Priority queue: [total_cost, i, j, remaining_k]
    const pq = new MinPriorityQueue({
        priority: (elem: [number, number, number, number]) => elem[0]
    });

    // Distance matrix: dist[i][j][k] = min cost to reach (i,j) with k teleports left
    const dist: number[][][] = Array.from({ length: m }, () => 
        Array.from({ length: n }, () => 
            Array(k + 1).fill(Infinity)
        )
    );

    // Initialize the starting point
    pq.enqueue([0, 0, 0, k]);
    dist[0][0][k] = 0;

    while (!pq.isEmpty()) {
        const [cost, i, j, rem_k] = pq.dequeue().element;

        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        if (cost > dist[i][j][rem_k]) {
            continue;
        }

        // Normal moves
        for (const [di, dj] of dirs) {
            const ni = i + di;
            const nj = j + dj;
            if (ni < m && nj < n) {
                const new_cost = cost + grid[ni][nj];
                if (new_cost < dist[ni][nj][rem_k]) {
                    dist[ni][nj][rem_k] = new_cost;
                    pq.enqueue([new_cost, ni, nj, rem_k]);
                }
            }
        }

        // Teleport move if remaining teleports > 0
        if (rem_k > 0) {
            for (let ni = 0; ni < m; ni++) {
                for (let nj = 0; nj < n; nj++) {
                    if (ni === i && nj === j) continue;
                    if (grid[ni][nj] <= grid[i][j]) {
                        if (cost < dist[ni][nj][rem_k - 1]) {
                            dist[ni][nj][rem_k - 1] = cost;
                            pq.enqueue([cost, ni, nj, rem_k - 1]);
                        }
                    }
                }
            }
        }
    }

    // Should not reach here if there's a valid path
    return -1;
}

// MinPriorityQueue implementation for TypeScript
class MinPriorityQueue<T> {
    private heap: { element: T; priority: number }[] = [];
    private compare: (a: number, b: number) => number;

    constructor(config: { priority: (elem: T) => number }) {
        this.compare = (a, b) => a - b;
        this.enqueue = (element: T) => {
            const priority = config.priority(element);
            this.heap.push({ element, priority });
            this.bubbleUp(this.heap.length - 1);
        };
        this.dequeue = () => {
            const min = this.heap[0];
            const end = this.heap.pop();
            if (this.heap.length > 0 && end) {
                this.heap[0] = end;
                this.bubbleDown(0);
            }
            return min;
        };
        this.isEmpty = () => this.heap.length === 0;
    }

    private bubbleUp(index: number) {
        const element = this.heap[index];
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            const parent = this.heap[parentIndex];
            if (this.compare(element.priority, parent.priority) >= 0) break;
            this.heap[index] = parent;
            index = parentIndex;
        }
        this.heap[index] = element;
    }

    private bubbleDown(index: number) {
        const length = this.heap.length;
        const element = this.heap[index];
        while (true) {
            const leftChildIndex = 2 * index + 1;
            const rightChildIndex = 2 * index + 2;
            let leftChild: { element: T; priority: number } | undefined;
            let rightChild: { element: T; priority: number } | undefined;
            let swap = null;

            if (leftChildIndex < length) {
                leftChild = this.heap[leftChildIndex];
                if (this.compare(leftChild.priority, element.priority) < 0) {
                    swap = leftChildIndex;
                }
            }

            if (rightChildIndex < length) {
                rightChild = this.heap[rightChildIndex];
                if (
                    (swap === null && this.compare(rightChild.priority, element.priority) < 0) ||
                    (swap !== null && leftChild && this.compare(rightChild.priority, leftChild.priority) < 0)
                ) {
                    swap = rightChildIndex;
                }
            }

            if (swap === null) break;
            this.heap[index] = this.heap[swap];
            index = swap;
        }
        this.heap[index] = element;
    }
}
