    pq.emplace(0, 0, 0, k);
    dist[0][0][k] = 0;

    while (!pq.empty()) {
        auto [cost, i, j, rem_k] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return cost;
